<script setup>
import { ref } from "vue";
import { useRouter } from "vue-router";

const router = useRouter();

const email = ref("");
const password = ref("");
const errorMsg = ref("");
const loading = ref(false);

const handleLogin = async () => {

  if (!email.value || !password.value) {
    errorMsg.value = "Please enter your credentials";
    return;
  }

  loading.value = true;
  errorMsg.value = "";

  try {
    const response = await fetch(
      "http://localhost:4000/api/v1/accounts/login",
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          email: email.value,
          password: password.value,
        }),
      },
    );

    const data = await response.json();
    console.log("Response OK:", response.ok);
    console.log("Response:", data);

    if (response.ok) {
      console.log("Login success!");
      
      localStorage.setItem("isLoggedIn", "true");
      localStorage.setItem("user_email", data.account.email);
      localStorage.setItem("user_id", data.account.id);

      console.log(localStorage.getItem("isLoggedIn"));

      console.log("Before push");
await router.push("/dashboard");
console.log("After push");
    } else {
      errorMsg.value = data.message;
    }
  } catch (error) {
    console.error(error);
    errorMsg.value = "Unable to connect to the server.";
  } finally {
    loading.value = false;
  }
};
</script>

<template>
  <div class="auth-page">
    <div class="glass-container">
      <!-- Left: Logo + Welcome -->
      <div class="brand-section">
        <div class="logo-wrap">
          <img
            src="data:image/png;base64,"
            alt="Ateneo de Naga University"
            class="ateneo-logo"
          />
        </div>
        <div class="welcome-text">Welcome!</div>
      </div>

      <!-- Right: Form -->
      <div class="form-section">
        <div class="form-card">
          <!-- GatePass Logo -->
          <div class="logo-row">
            <div class="logo-icon">
              <svg width="22" height="22" viewBox="0 0 22 22" fill="none">
                <circle
                  cx="11"
                  cy="11"
                  r="10"
                  stroke="#2563eb"
                  stroke-width="2"
                />
                <path
                  d="M7 11 A4 4 0 1 1 15 11"
                  stroke="#2563eb"
                  stroke-width="2"
                  fill="none"
                  stroke-linecap="round"
                />
                <circle cx="11" cy="7" r="1.5" fill="#2563eb" />
              </svg>
            </div>
            <span class="logo-label">Ateneo de Naga GatePass</span>
          </div>

          <form @submit.prevent="handleLogin" class="auth-form">
            <div class="input-group">
              <label>Email</label>
              <input
                v-model="email"
                type="email"
                placeholder="name@gmail.com"
                required
              />
            </div>

            <div class="input-group">
              <label>Password</label>
              <input
                v-model="password"
                type="password"
                placeholder="Enter your password"
                required
              />
            </div>

            <div v-if="errorMsg" class="error-msg">{{ errorMsg }}</div>

            <button type="submit" class="submit-btn" :disabled="loading">
              {{ loading ? "Signing in..." : "Sign In" }}
            </button>

            <div class="signup-link">
              No account yet? <router-link to="/signup">Sign up</router-link>
            </div>
          </form>
        </div>
      </div>
    </div>
  </div>
</template>

